  ? T
  : T extends readonly (infer U)[]
  ? readonly DeepReadonly<U>[]
  : T extends object
  ? { readonly [P in keyof T]: DeepReadonly<T[P]> }
  : T;

type DeepPartial<T> = T extends (...args: any[]) => any
  ? T
  : T extends (infer U)[]
  ? DeepPartial<U>[]
  : T extends object
  ? { [P in keyof T]?: DeepPartial<T[P]> }
  : T;

