// intentionally loose - it exists so the overloads above can be satisfied
// Hint: fn.length gives you the declared arity of `fn` at runtime
// Hint: accumulate arguments in a closure array and call `fn(...accumulated)`
// once you have `fn.length` of them

solution:
function curry<A, B, R>(fn: (a: A, b: B) => R): (a: A) => (b: B) => R;
function curry<A, B, C, R>(fn: (a: A, b: B, c: C) => R): (a: A) => (b: B) => (c: C) => R;
function curry(fn: (...args: any[]) => any): any {
  const arity = fn.length;

  function curried(...accumulated: any[]): any {
    if (accumulated.length >= arity) {
      return fn(...accumulated);
    }
    return (nextArg: any) => curried(...accumulated, nextArg);
  }

  return (firstArg: any) => curried(firstArg);
}

// Usage
function add3(a: number, b: number, c: number): number {
  return a + b + c;
}
const curriedAdd3 = curry(add3);
const result = curriedAdd3(1)(2)(3); // 6

function formatName(first: string, last: string): string {
  return `${last}, ${first}`;
}
const curriedFormat = curry(formatName);
const formatted = curriedFormat('John')('Doe'); // 'Doe, John'

