solution:
type ColumnType = 'string' | 'number' | 'boolean';
type SchemaValueType<T extends ColumnType> = T extends 'string'
  ? string
  : T extends 'number'
  ? number
  : boolean;

type Schema = Record<string, { type: ColumnType }>;

// Pick just the selected keys out of the schema, then map each to its
// runtime value type.
type SelectedRow<S extends Schema, Cols extends (keyof S)[]> = {
  [K in Cols[number]]: SchemaValueType<S[K]['type']>;
};

interface QueryBuilder<S extends Schema, Cols extends (keyof S)[]> {
  where<K extends keyof S>(
    column: K,
    value: SchemaValueType<S[K]['type']>
  ): QueryBuilder<S, Cols>;
  execute(): SelectedRow<S, Cols>[];
}

function createQueryBuilder<S extends Schema>(schema: S) {
  return {
    select<Cols extends (keyof S)[]>(...cols: Cols): QueryBuilder<S, Cols> {
      const filters: [keyof S, unknown][] = [];
      const builder: QueryBuilder<S, Cols> = {
        where(column, value) {
          filters.push([column, value]);
          return builder;
        },
        execute() {
          // Runtime stub: in a real implementation this would run against
          // actual data using `cols` and `filters`. Returning [] keeps the
          // focus on the type-level contract.
          return [] as SelectedRow<S, Cols>[];
        },
      };
      return builder;
    },
  };
}

// Test
const users = createQueryBuilder({
  id: { type: 'number' },
  name: { type: 'string' },
  active: { type: 'boolean' },
} as const);

const rows = users.select('id', 'name').where('active', true).execute();
// rows: { id: number; name: string }[]

description.en:
Implement a `deepMerge<A, B>` function and matching `DeepMerge<A, B>` type that recursively merges two objects, where properties from `B` take precedence over `A` on conflicting keys, nested objects are merged recursively (not overwritten wholesale), and arrays are replaced (not concatenated or merged element-wise).

**Requirements:**
- For keys present in both `A` and `B`: if both values are plain objects, merge recursively; otherwise `B`'s value wins
- For keys present only in `A` or only in `B`: keep as-is
- Arrays count as "not a plain object" for merge purposes - `B`'s array fully replaces `A`'s array
- The resulting type must be computed structurally, not just widened to `A & B`

**Function signature:**
```typescript
type DeepMerge<A, B> = /* your implementation */;
function deepMerge<A extends object, B extends object>(a: A, b: B): DeepMerge<A, B>;
```

**Example:**
```typescript
const defaults = {
  server: { port: 3000, host: 'localhost' },
  features: ['logging'],
  debug: false,
};
const overrides = {
  server: { port: 8080 },
  features: ['logging', 'metrics'],
};

const config = deepMerge(defaults, overrides);
// type: { server: { port: number; host: string }; features: string[]; debug: boolean }
// value: { server: { port: 8080, host: 'localhost' }, features: ['logging', 'metrics'], debug: false }
```

**Edge cases:**
- A key whose value is an object in `A` but a primitive in `B` (or vice versa) - `B` should win outright, no attempted recursive merge
- Merging with an empty object on either side
- A deeply nested (3+ levels) conflicting key path

description.ru:
Реализуйте функцию `deepMerge<A, B>` и соответствующий тип `DeepMerge<A, B>`, которые рекурсивно сливают два объекта: свойства из `B` имеют приоритет над `A` при конфликте ключей, вложенные объекты сливаются рекурсивно (а не перезаписываются целиком), а массивы заменяются целиком (не конкатенируются и не сливаются поэлементно).

**Требования:**
- Для ключей, присутствующих и в `A`, и в `B`: если оба значения - обычные объекты, слить рекурсивно; иначе побеждает значение из `B`
- Для ключей, присутствующих только в `A` или только в `B`: оставить как есть
- Массивы считаются «не обычным объектом» для целей слияния - массив из `B` полностью заменяет массив из `A`
- Итоговый тип должен вычисляться структурно, а не просто расширяться до `A & B`

**Сигнатура функции:**
```typescript
type DeepMerge<A, B> = /* твоя реализация */;
function deepMerge<A extends object, B extends object>(a: A, b: B): DeepMerge<A, B>;
```

**Пример:**
```typescript
const defaults = {
  server: { port: 3000, host: 'localhost' },
  features: ['logging'],
  debug: false,
};
const overrides = {
  server: { port: 8080 },
  features: ['logging', 'metrics'],
};

const config = deepMerge(defaults, overrides);
// тип: { server: { port: number; host: string }; features: string[]; debug: boolean }
// значение: { server: { port: 8080, host: 'localhost' }, features: ['logging', 'metrics'], debug: false }
```

**Граничные случаи:**
- Ключ, чьё значение - объект в `A`, но примитив в `B` (или наоборот) - `B` должен полностью победить, без попытки рекурсивного слияния
- Слияние с пустым объектом с любой из сторон
- Глубоко вложенный (3+ уровня) конфликтующий путь ключа

starterCode:
type IsPlainObject<T> = T extends readonly any[]
  ? false
  : T extends object
  ? true
  : false;

// Implement the recursive merge type.
type DeepMerge<A, B> = any; // implement here

function deepMerge<A extends object, B extends object>(a: A, b: B): DeepMerge<A, B> {
  // implement runtime merge
  return {} as any;
}

solution:
type IsPlainObject<T> = T extends readonly any[]
  ? false
  : T extends object
  ? true
  : false;

type DeepMerge<A, B> = {
  [K in keyof A | keyof B]: K extends keyof B
    ? K extends keyof A
      ? IsPlainObject<A[K]> extends true
        ? IsPlainObject<B[K]> extends true
          ? DeepMerge<A[K], B[K]>
          : B[K]
        : B[K]
      : B[K]
    : K extends keyof A
    ? A[K]
    : never;
};

function isPlainObject(value: unknown): value is Record<string, unknown> {
  return (
    typeof value === 'object' &&
    value !== null &&
    !Array.isArray(value)
  );
}

function deepMerge<A extends object, B extends object>(a: A, b: B): DeepMerge<A, B> {
  const result: Record<string, unknown> = { ...a };
  for (const key of Object.keys(b)) {
    const aVal = (a as Record<string, unknown>)[key];
    const bVal = (b as Record<string, unknown>)[key];
    if (isPlainObject(aVal) && isPlainObject(bVal)) {
      result[key] = deepMerge(aVal, bVal);
    } else {
      result[key] = bVal;
    }
  }
  return result as DeepMerge<A, B>;
}

// Test
const defaults = {
  server: { port: 3000, host: 'localhost' },
  features: ['logging'],
  debug: false,
};
const overrides = {
  server: { port: 8080 },
  features: ['logging', 'metrics'],
};

const config = deepMerge(defaults, overrides);
// { server: { port: number; host: string }; features: string[]; debug: boolean }

description.en:
Implement a `ParseQueryString<T>` type-level parser that converts a URL query string literal type into a typed object of key-value pairs, plus a matching runtime `parseQueryString` function whose return type is inferred from the literal string argument.

**Requirements:**
- Split on `&` to get individual `key=value` pairs
- Split each pair on `=` to get key and value
- A key with no `=value` part (a bare flag) should map to `string` (empty string at runtime, but typed permissively as `string`)
- Repeated keys should produce a union type value for that key, not silently overwrite
- Values must remain string-typed (no automatic number/boolean coercion at the type level - that's out of scope here)

**Function signature:**
```typescript
type ParseQueryString<T extends string> = /* your implementation */;
function parseQueryString<T extends string>(query: T): ParseQueryString<T>;
```

**Example:**
```typescript
type Parsed = ParseQueryString<'sort=asc&page=2&filter=active&filter=recent'>;
// { sort: string; page: string; filter: string }
// (each value's type is 'string' - the union collapses because all values are string)

const result = parseQueryString('sort=asc&page=2');
// result: { sort: string; page: string }
result.sort; // 'asc' at runtime, typed as string

type WithFlag = ParseQueryString<'debug&verbose=true'>;
// { debug: string; verbose: string }
```

**Edge cases:**
- Empty query string `''`
- A single key with no value and no trailing `&` (`'debug'`)
- A value that itself contains an `=` character (e.g. `'redirect=/path?x=1'`) - decide and document how your split handles this

description.ru:
Реализуйте тип-парсер `ParseQueryString<T>` на уровне типов, который превращает литеральный строковый тип query string в типизированный объект пар ключ-значение, плюс соответствующую рантайм-функцию `parseQueryString`, чей тип возврата выводится из литерального строкового аргумента.

**Требования:**
- Разбить по `&`, чтобы получить отдельные пары `key=value`
- Разбить каждую пару по `=`, чтобы получить ключ и значение
- Ключ без части `=value` (голый флаг) должен маппиться на `string` (пустая строка в рантайме, но типизирован разрешающе как `string`)
- Повторяющиеся ключи должны давать union-тип значения для этого ключа, а не молча перезаписываться
- Значения должны оставаться строкового типа (без автоматического приведения к number/boolean на уровне типов - это вне рамок задачи)

**Сигнатура функции:**
```typescript
type ParseQueryString<T extends string> = /* твоя реализация */;
function parseQueryString<T extends string>(query: T): ParseQueryString<T>;
```

**Пример:**
```typescript
type Parsed = ParseQueryString<'sort=asc&page=2&filter=active&filter=recent'>;
// { sort: string; page: string; filter: string }
// (тип каждого значения - 'string' - union схлопывается, потому что все значения string)

const result = parseQueryString('sort=asc&page=2');
// result: { sort: string; page: string }
result.sort; // 'asc' в рантайме, типизирован как string

type WithFlag = ParseQueryString<'debug&verbose=true'>;
// { debug: string; verbose: string }
```

**Граничные случаи:**
- Пустая query string `''`
- Один ключ без значения и без завершающего `&` (`'debug'`)
- Значение, которое само содержит символ `=` (например `'redirect=/path?x=1'`) - реши и задокументируй, как твой разбор это обрабатывает

starterCode:
// Split a string literal on a delimiter, at the type level.
type Split<S extends string, D extends string> = S extends `${infer Head}${D}${infer Tail}`
  ? [Head, ...Split<Tail, D>]
  : [S];

// Implement: parse one 'key=value' or bare 'key' pair into a { key: string } shape.
type ParsePair<Pair extends string> = any; // implement here

// Implement: split the full query string on '&' and merge all pairs into one object.
type ParseQueryString<T extends string> = any; // implement here

function parseQueryString<T extends string>(query: T): ParseQueryString<T> {
  // implement runtime parsing
  return {} as any;
}

solution:
type Split<S extends string, D extends string> = S extends `${infer Head}${D}${infer Tail}`
  ? [Head, ...Split<Tail, D>]
  : [S];

// Parse one pair: 'key=value' -> { key: string }, or bare 'key' -> { key: string }
type ParsePair<Pair extends string> = Pair extends `${infer Key}=${infer _Value}`
  ? Key extends ''
    ? {}
    : { [K in Key]: string }
  : Pair extends ''
  ? {}
  : { [K in Pair]: string };

// Fold an array of single-pair object types into one merged object type.
type MergePairs<Pairs extends readonly unknown[]> = Pairs extends [
  infer Head,
  ...infer Rest
]
  ? Head & MergePairs<Rest>
  : {};

type ParseQueryString<T extends string> = T extends ''
  ? {}
  : {
      [K in keyof MergePairs<Split<T, '&'>>]: string;
    };

function parseQueryString<T extends string>(query: T): ParseQueryString<T> {
  const result: Record<string, string> = {};
  if (query === '') return result as ParseQueryString<T>;
  for (const pair of query.split('&')) {
    const eqIndex = pair.indexOf('=');
    if (eqIndex === -1) {
      result[pair] = '';
    } else {
      const key = pair.slice(0, eqIndex);
      const value = pair.slice(eqIndex + 1);
      result[key] = value;
    }
  }
  return result as ParseQueryString<T>;
}

// Test
type Parsed = ParseQueryString<'sort=asc&page=2&filter=active&filter=recent'>;
// { sort: string; page: string; filter: string }

const result = parseQueryString('sort=asc&page=2');
result.sort; // 'asc'

type WithFlag = ParseQueryString<'debug&verbose=true'>;
// { debug: string; verbose: string }

description.en:
Build a `createMachine` factory that takes a map of states to their allowed transitions, and returns a machine whose `.send(event)` method only accepts events valid for the *current* state - determined statically for known states, and validated at runtime as the state actually changes.

**Requirements:**
- Machine definition is `{ [state: string]: { [event: string]: string /* next state */ } }`
- `machine.send(event)` should be typed to only accept event names valid for the machine's *initial* declared state at the type level (compile-time narrowing to the current runtime state across `.send()` calls is out of scope - that requires a stateful type per instance, which TypeScript can't track through mutation; document this limitation rather than faking it)
- `machine.getState()` returns the current state as a string, narrowed to the union of all state names
- Calling `.send()` with an event not defined for the machine's states anywhere should fail to compile
- At runtime, sending a valid-looking event that isn't valid for the *actual current* state should throw, not silently no-op

**Function signature:**
```typescript
function createMachine<
  States extends Record<string, Record<string, string>>
>(config: {
  initial: keyof States;
  states: States;
}): {
  getState(): keyof States;
  send(event: EventsOf<States>): void;
};
```

**Example:**
```typescript
const traffic = createMachine({
  initial: 'red',
  states: {
    red: { next: 'green' },
    green: { next: 'yellow' },
    yellow: { next: 'red' },
  },
});

traffic.send('next'); // OK, 'next' is a valid event name somewhere in the machine
traffic.getState(); // 'green' at runtime, typed as 'red' | 'green' | 'yellow'

// @ts-expect-error - 'skip' isn't an event defined anywhere in the machine
traffic.send('skip');
```

**Edge cases:**
- A state with zero outgoing transitions (terminal state) - `.send()` from there should throw at runtime for any event
- Two different states sharing the same event name but transitioning to different next states
- `getState()` called immediately after construction, before any `.send()`

description.ru:
Постройте фабрику `createMachine`, которая принимает карту состояний и их допустимых переходов и возвращает машину, чей метод `.send(event)` принимает только события, допустимые для *текущего* состояния - статически определяемые для известных состояний и проверяемые в рантайме по мере фактической смены состояния.

**Требования:**
- Определение машины: `{ [state: string]: { [event: string]: string /* следующее состояние */ } }`
- `machine.send(event)` должен быть типизирован так, чтобы принимать только имена событий, допустимые где-либо в машине на уровне типов (сужение на этапе компиляции до текущего рантайм-состояния между вызовами `.send()` вне рамок задачи - это требует состояния типа для каждого инстанса, что TypeScript не может отследить через мутацию; задокументируй это ограничение, а не имитируй его)
- `machine.getState()` возвращает текущее состояние как строку, суженную до union всех имён состояний
- Вызов `.send()` с событием, не определённым нигде в состояниях машины, не должен компилироваться
- В рантайме отправка похожего на валидное события, которое недопустимо для *реального текущего* состояния, должна бросать исключение, а не молча ничего не делать

**Сигнатура функции:**
```typescript
function createMachine<
  States extends Record<string, Record<string, string>>
>(config: {
  initial: keyof States;
  states: States;
}): {
  getState(): keyof States;
  send(event: EventsOf<States>): void;
};
```

**Пример:**
```typescript
const traffic = createMachine({
  initial: 'red',
  states: {
    red: { next: 'green' },
    green: { next: 'yellow' },
    yellow: { next: 'red' },
  },
});

traffic.send('next'); // OK, 'next' - валидное имя события где-то в машине
traffic.getState(); // 'green' в рантайме, типизирован как 'red' | 'green' | 'yellow'

// @ts-expect-error - 'skip' не является событием, определённым где-либо в машине
traffic.send('skip');
```

**Граничные случаи:**
- Состояние без исходящих переходов (терминальное состояние) - `.send()` из него должен бросать исключение в рантайме для любого события
- Два разных состояния с одинаковым именем события, ведущие в разные следующие состояния
- `getState()`, вызванный сразу после создания, до любого `.send()`

