type StatesConfig = Record<string, Record<string, string>>;

// Implement: the union of every event name that appears in any state's
// transition map.
type EventsOf<States extends StatesConfig> = any; // implement here

function createMachine<States extends StatesConfig>(config: {
  initial: keyof States;
  states: States;
}) {
  let current: keyof States = config.initial;

  return {
    getState(): keyof States {
      return current;
    },
    send(event: EventsOf<States>): void {
      // implement runtime transition + throw on invalid transition
    },
  };
}

solution:
type StatesConfig = Record<string, Record<string, string>>;

// Union of every event name across every state's transition map.
type EventsOf<States extends StatesConfig> = {
  [S in keyof States]: keyof States[S];
}[keyof States];

function createMachine<States extends StatesConfig>(config: {
  initial: keyof States;
  states: States;
}) {
  let current: keyof States = config.initial;

  return {
    getState(): keyof States {
      return current;
    },
    send(event: EventsOf<States>): void {
      const transitions = config.states[current];
      const next = transitions[event as string];
      if (next === undefined) {
        throw new Error(
          `Invalid transition: event "${String(event)}" is not valid from state "${String(current)}"`
        );
      }
      current = next as keyof States;
    },
  };
}

// Test
const traffic = createMachine({
  initial: 'red',
  states: {
    red: { next: 'green' },
    green: { next: 'yellow' },
    yellow: { next: 'red' },
  },
});

traffic.send('next'); // OK - narrows to green at runtime
traffic.getState(); // 'red' | 'green' | 'yellow'

try {
  // Compiles because 'next' is a valid event somewhere in the machine,
  // but at runtime a terminal-state machine would throw here.
} catch {}

