type MiddlewareFn<Current extends object, Added extends object> = (
  ctx: Current
) => Added | void;

interface Pipeline<Initial extends object, Current extends object> {
  use<Added extends object>(
    mw: MiddlewareFn<Current, Added>
  ): Pipeline<Initial, Current & Added>;
  run(initial: Initial): Current;
}

function createPipeline<Ctx extends object>(): Pipeline<Ctx, Ctx> {
  const middlewares: ((ctx: any) => any)[] = [];

  function build(): Pipeline<Ctx, any> {
    return {
      use(mw) {
        // implement: register mw, return a new pipeline whose type has
        // the accumulated Added merged in
        return {} as any;
      },
      run(initial) {
        // implement: fold middlewares over initial context
        return {} as any;
      },
    };
  }

  return build();
}

solution:
type MiddlewareFn<Current extends object, Added extends object> = (
  ctx: Current
) => Added | void;

interface Pipeline<Initial extends object, Current extends object> {
  use<Added extends object>(
    mw: MiddlewareFn<Current, Added>
  ): Pipeline<Initial, Current & Added>;
  run(initial: Initial): Current;
}

function createPipeline<Ctx extends object>(): Pipeline<Ctx, Ctx> {
  function build(middlewares: ((ctx: any) => any)[]): Pipeline<Ctx, any> {
    return {
      use(mw: (ctx: any) => any) {
        return build([...middlewares, mw]);
      },
      run(initial: any) {
        let ctx = initial;
        for (const mw of middlewares) {
          const result = mw(ctx);
          if (result !== undefined && result !== null) {
            ctx = { ...ctx, ...result };
          }
        }
        return ctx;
      },
    };
  }

  return build([]);
}

// Test
const pipeline = createPipeline<{ userId: string }>()
  .use((ctx) => ({ user: { id: ctx.userId, name: 'loaded' } }))
  .use((ctx) => ({ permissions: ctx.user.name === 'loaded' ? ['read'] : [] }))
  .use((ctx) => {
    console.log(ctx.permissions);
  });

const result = pipeline.run({ userId: 'abc' });
// { userId: string; user: { id: string; name: string }; permissions: string[] }
